  function suggestCommand(command) {
    if (/^git add(\s|$)/.test(command) && command !== 'git add README.md' && command !== 'git add README.md && git commit && git push') {
      return 'git add README.md';
    }
    if (/^git commit(\s|$)/.test(command) && command !== 'git commit') {
      return 'git commit';
    }
    return null;
  }

  async function executeTerminalCommand(rawCommand) {
    const command = rawCommand.trim();
    if (!command) return;

    state.lastCommand = command;
    state.lastOutput = [];
    state.statusMessage = null;

    if (!state.installed && command.startsWith('last-of-readme ')) {
      state.lastOutput.push('command not found (demo uninstalled)');
      render();
      return;
    }

    const suggestion = suggestCommand(command);
    if (suggestion) {
      state.lastOutput.push(`try: ${suggestion}`);
      render();
      return;
    }

    const handler = commands[command];
    if (!handler) {
      state.lastCommand = null;
      state.statusMessage = 'select a command from the palette above';
      render();
      return;
    }

    try {
      for (const line of await handler()) {
        state.lastOutput.push(line);
      }
    } catch (error) {
      state.lastOutput.push(`error: ${error && error.message ? error.message : String(error)}`);
    }
    render();
  }

  async function resolveNpmLink(event) {
    const anchor = event.target.closest('a[href*="readme-resolver-driver.html"]');
    if (!anchor) return;
    event.preventDefault();
    const url = new URL(anchor.href);
    const version = url.searchParams.get('v');
    const contract = url.searchParams.get('contract') || 'until-next';
    const urlPath = url.searchParams.get('urlPath') || '';
    const resolver = window.LastOfReadmeResolver;
    if (!resolver || typeof resolver.resolveReadmeLink !== 'function') {
      state.statusMessage = 'resolver core is not available';
      render();
      return;
    }

    const outcome = await resolver.resolveReadmeLink({
      remoteRepository: createDemoRemoteRepository(),
      repositoryPage: createDemoRepositoryPage(urlPath),
      version,
      contract,
    });

    if (outcome.action === 'redirect') {
      state.githubSelection = extractTargetFromBrowserUrl(outcome.url);
      state.statusMessage = 'link resolved — see GitHub pane';
    } else {
      state.githubSelection = { message: outcome.page.message, links: outcome.page.links };
      state.statusMessage = outcome.page.message || 'no matching version found — see GitHub pane';
    }
    render();
  }

  function extractTargetFromBrowserUrl(url) {
    const match = String(url).match(/\/tree\/([^/]+)(?:\/(.*))?$/);
    if (!match) return { message: url };
    const ref = decodeURIComponent(match[1]);
    const path = match[2] ? decodeURIComponent(match[2]) : 'README.md';
    const commit = state.tags[ref] || state.branches[ref] || ref;
    return { ref, commit, path, url };
  }

